static const float b_mu[1] = {
    -0.03844720f
};

static float droq_last_applied_voltage = 0.0f;
static int droq_stack_initialized = 0;
static float droq_frame_stack[DROQ_OBS_DIM];

static inline float droq_relu(float x) { return x > 0.0f ? x : 0.0f; }

static inline float droq_clamp(float x, float lo, float hi) {
    if (x < lo) return lo;
    if (x > hi) return hi;
    return x;
}

static inline float droq_wrap_pi(float x) {
    while (x > (float)M_PI) x -= 2.0f * (float)M_PI;
    while (x < -(float)M_PI) x += 2.0f * (float)M_PI;
    return x;
}

static float droq_deadzone(float voltage) {
    if (voltage > DEADZONE_THRESH) voltage += DEADZONE_VAL;
    else if (voltage < -DEADZONE_THRESH) voltage -= DEADZONE_VAL;
    else voltage = 0.0f;
    return droq_clamp(voltage, -PROP_VCAP, PROP_VCAP);
}

static void droq_reset_state(void) {
    droq_last_applied_voltage = 0.0f;
    droq_stack_initialized = 0;
    for (int i = 0; i < DROQ_OBS_DIM; i++) droq_frame_stack[i] = 0.0f;
}

static void droq_build_raw_obs(float raw[DROQ_PER_FRAME_DIM],
                               float pend_pos, float arm_pos,
                               float pend_vel, float arm_vel) {
    raw[0] = cosf(pend_pos);
    raw[1] = sinf(pend_pos);
    raw[2] = cosf(arm_pos);
    raw[3] = sinf(arm_pos);
    raw[4] = pend_vel / VEL_NORM_PEND;
    raw[5] = arm_vel / VEL_NORM_ARM;
    raw[6] = droq_clamp(droq_last_applied_voltage / RL_VCAP, -1.0f, 1.0f);
}

static void droq_update_obs_stack(float obs[DROQ_OBS_DIM], const float raw[DROQ_PER_FRAME_DIM]) {
    if (!droq_stack_initialized) {
        for (int f = 0; f < DROQ_FRAME_STACK; f++) {
            for (int j = 0; j < DROQ_PER_FRAME_DIM; j++) {
                droq_frame_stack[f * DROQ_PER_FRAME_DIM + j] = raw[j];
            }
        }
        droq_stack_initialized = 1;
    } else {
        for (int i = 0; i < DROQ_OBS_DIM - DROQ_PER_FRAME_DIM; i++) {
            droq_frame_stack[i] = droq_frame_stack[i + DROQ_PER_FRAME_DIM];
        }
        for (int j = 0; j < DROQ_PER_FRAME_DIM; j++) {
            droq_frame_stack[DROQ_OBS_DIM - DROQ_PER_FRAME_DIM + j] = raw[j];
        }
    }
    for (int i = 0; i < DROQ_OBS_DIM; i++) obs[i] = droq_frame_stack[i];
}

static float droq_actor_forward(const float obs[DROQ_OBS_DIM]) {
    float h0[256];
    for (int i = 0; i < 256; i++) {
        float sum = b_hidden_0[i];
        for (int j = 0; j < 21; j++) {
            sum += w_hidden_0[i * 21 + j] * obs[j];
        }
        h0[i] = droq_relu(sum);
    }

    float h1[256];
    for (int i = 0; i < 256; i++) {
        float sum = b_hidden_1[i];
        for (int j = 0; j < 256; j++) {
            sum += w_hidden_1[i * 256 + j] * h0[j];
        }
        h1[i] = droq_relu(sum);
    }

    float mu = b_mu[0];
    for (int j = 0; j < 256; j++) {
        mu += w_mu[j] * h1[j];
    }
    if (MU_HAS_HARDTANH) mu = droq_clamp(mu, MU_CLIP_MIN, MU_CLIP_MAX);
    return tanhf(mu);
}

static float droq_proportional_pre_voltage(float arm_pos, float arm_vel,
                                          float pend_pos, float pend_vel) {
    float u = -(K1 * arm_pos + K2 * arm_vel + K3 * pend_pos + K4 * pend_vel + K5 * droq_last_applied_voltage);
    return droq_clamp(u, -PROP_VCAP, PROP_VCAP);
}

static float droq_output_voltage(float pre_deadzone_voltage, float *applied_voltage) {
    float applied = droq_deadzone(pre_deadzone_voltage);
    *applied_voltage = applied;
    if (DROQ_OUTPUT_PRE_DEADZONE) return pre_deadzone_voltage;
    return applied;
}

/*
 * Full control pipeline. Call once per control tick on the controller ESP.
 * Returns voltage command. If DROQ_OUTPUT_PRE_DEADZONE=1, the plant/PWM layer
 * should apply deadzone compensation. Otherwise this returns the final voltage.
 */
static float droq_control_step(float pend_pos, float arm_pos,
                               float pend_vel, float arm_vel,
                               int *controller) {
    pend_pos = droq_wrap_pi(pend_pos);
    float abs_pend = fabsf(pend_pos);
    if (abs_pend > SAFE_ANGLE) {
        if (controller) *controller = DROQ_CTRL_FALLEN;
        droq_reset_state();
        return 0.0f;
    }

    float raw[DROQ_PER_FRAME_DIM];
    float obs[DROQ_OBS_DIM];
    droq_build_raw_obs(raw, pend_pos, arm_pos, pend_vel, arm_vel);
    droq_update_obs_stack(obs, raw);

    float prop_pre = droq_proportional_pre_voltage(arm_pos, arm_vel, pend_pos, pend_vel);
    float selected_pre = prop_pre;

    if (abs_pend <= BLEND_INNER_RAD) {
        if (controller) *controller = DROQ_CTRL_RL;
        float action = droq_actor_forward(obs);
        selected_pre = droq_clamp(action * RL_VCAP, -RL_VOLTAGE_LIMIT, RL_VOLTAGE_LIMIT);
    } else if (abs_pend < RL_ANGLE_RAD) {
        if (controller) *controller = DROQ_CTRL_BLEND;
        float alpha = 1.0f - (abs_pend - BLEND_INNER_RAD) / (RL_ANGLE_RAD - BLEND_INNER_RAD);
        float action = droq_actor_forward(obs);
        float rl_pre = droq_clamp(action * RL_VCAP, -RL_VOLTAGE_LIMIT, RL_VOLTAGE_LIMIT);
        selected_pre = alpha * rl_pre + (1.0f - alpha) * prop_pre;
    } else {
        if (controller) *controller = DROQ_CTRL_PROPORTIONAL;
        selected_pre = prop_pre;
    }

    float applied = 0.0f;
    float command = droq_output_voltage(selected_pre, &applied);
    droq_last_applied_voltage = applied;
    return command;
}

